@startuml
abstract class Payment {
  amount: float
  date: Date
}
class MembershipFeePayment {
  contributionYear: int
}
class Donation
class Member {
  status: MemberStatus
}
class DistrictChapter
class StateChapter
class MembershipApplication {
  status: ApplicationStatus
}
class Committee
class Mandate {
  termOfOffice: String
}
class Campaign
class Deployment {
  numberOfHours: int
}
interface Notifiable
enum MemberStatus {
  active
  passive
  resigned
}
enum ApplicationStatus {
  received
  reviewed
  accepted
  rejected
}

StateChapter "1" *-- "1..*" DistrictChapter
DistrictChapter "1" *-- "1..*" Member
DistrictChapter "1" -- "0..*" MembershipApplication
DistrictChapter "1" -- "0..*" Campaign

Member "1" *-- "0..*" Payment
Notifiable <|.. Member
MembershipApplication "1" -- "0..1" Member : emerges from

Payment <|-- MembershipFeePayment
Payment <|-- Donation
Donation "0..*" o-- "0..1" Campaign : earmarked for

Committee "1" -- "0..*" Mandate
Mandate "1" -- "1" Member

(Member, Campaign) .. Deployment
@enduml

classDiagram
  class StateChapter
