    val gearbox = partDef(name = "Gearbox")
    val bms = partDef(name = "BatteryManagementSystem")
    val thermalManagementSystem = partDef(name = "ThermalManagementSystem")

    // Supertype for specialization
    val powerElectronics = partDef(name = "PowerElectronics")

    // Part with specialization
    val inverter = partDef(name = "Inverter")

    // Composite parts building up the hierarchy
    val batteryModule = partDef(name = "BatteryModule") {
        part(name = "cells", typeId = cell.id, multiplicity = "1..*")
    }

    val batteryPack = partDef(name = "HighVoltageBatteryPack") {
        part(name = "modules", typeId = batteryModule.id, multiplicity = "1..*")
    }

    val drivetrainSystem = partDef(name = "DrivetrainSystem") {
        part(name = "batteryPack", typeId = batteryPack.id)
        part(name = "inverter", typeId = inverter.id)
